import{_ as a,o as e,c as r,a4 as d}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"团队 AI 编程实践指南","description":"","frontmatter":{"title":"团队 AI 编程实践指南","date":"2026-07-08T00:00:00.000Z","tags":["AI编程","团队规范","效率提升"]},"headers":[],"relativePath":"work/ai-coding/index.md","filePath":"work/ai-coding/index.md","lastUpdated":1783652711000}'),h={name:"work/ai-coding/index.md"};function i(o,t,l,n,p,m){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="团队-ai-编程实践指南" tabindex="-1">团队 AI 编程实践指南 <a class="header-anchor" href="#团队-ai-编程实践指南" aria-label="Permalink to &quot;团队 AI 编程实践指南&quot;">​</a></h1><blockquote><p>从个人尝鲜到团队落地，AI 编程需要的不仅是工具，更是范式、规范和流程。</p></blockquote><hr><h2 id="三大核心问题" tabindex="-1">三大核心问题 <a class="header-anchor" href="#三大核心问题" aria-label="Permalink to &quot;三大核心问题&quot;">​</a></h2><h3 id="_1-ai-编程的范式和规范" tabindex="-1">1. AI 编程的范式和规范 <a class="header-anchor" href="#_1-ai-编程的范式和规范" aria-label="Permalink to &quot;1. AI 编程的范式和规范&quot;">​</a></h3><p>三种工作范式（Copilot/Agent/对话）、三大原则（人在环/上下文为王/可验证优先）、Prompt 五要素法、代码生成审查清单、安全红线</p><p>👉 <a href="./paradigm.html">AI 编程范式与规范</a></p><h3 id="_2-不同团队规模的规范" tabindex="-1">2. 不同团队规模的规范 <a class="header-anchor" href="#_2-不同团队规模的规范" aria-label="Permalink to &quot;2. 不同团队规模的规范&quot;">​</a></h3><p>小型团队（2-3人）：统一标准、互相审查 中型团队（5-10人）：流程化、防冲突 大型团队（10-20人）：分层治理、合规安全</p><p>👉 <a href="./team-spec.html">团队 AI 编程规范</a></p><h3 id="_3-ai-编程的扩展应用" tabindex="-1">3. AI 编程的扩展应用 <a class="header-anchor" href="#_3-ai-编程的扩展应用" aria-label="Permalink to &quot;3. AI 编程的扩展应用&quot;">​</a></h3><p>从需求到运维全生命周期：需求拆解、接口设计、测试生成、文档编写、日志分析、运维自动化、项目管理、技术培训</p><p>👉 <a href="./extended-use.html">AI 编程的扩展应用</a></p><hr><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你想了解什么</th><th>去哪里看</th></tr></thead><tbody><tr><td>AI 编程的三种模式是什么</td><td><a href="./paradigm.html#一ai-编程的核心范式">范式与规范 → 三种工作范式</a></td></tr><tr><td>怎么写好 Prompt</td><td><a href="./paradigm.html#二ai-编程规范">范式与规范 → Prompt 规范</a></td></tr><tr><td>AI 代码怎么审查</td><td><a href="./paradigm.html#22-代码生成规范">范式与规范 → 代码生成规范</a></td></tr><tr><td>小团队怎么避免混乱</td><td><a href="./team-spec.html#二小型团队23-人">团队规范 → 小型团队</a></td></tr><tr><td>中团队怎么防止冲突</td><td><a href="./team-spec.html#三中型团队510-人">团队规范 → 中型团队</a></td></tr><tr><td>大团队怎么治理</td><td><a href="./team-spec.html#四大型团队1020-人">团队规范 → 大型团队</a></td></tr><tr><td>AI 还能帮我做什么</td><td><a href="./extended-use.html">扩展应用</a></td></tr><tr><td>怎么推广到团队</td><td><a href="./team-spec.html#六推广路线图">团队规范 → 推广路线图</a></td></tr></tbody></table>',16)])])}const _=a(h,[["render",i]]);export{c as __pageData,_ as default};
